import{_ as a,c as o,o as r,aA as s}from"./chunks/framework.CdLCptfM.js";const i="/RadialBasisFunctions.jl/previews/PR144/assets/hessian_phs_matched.jA8D-aWY.png",t="/RadialBasisFunctions.jl/previews/PR144/assets/hessian_phs_polydeg_sweep.KhfcZ9WG.png",c="/RadialBasisFunctions.jl/previews/PR144/assets/jacobian_phs_matched.CccIl5Mq.png",n="/RadialBasisFunctions.jl/previews/PR144/assets/jacobian_phs_polydeg_sweep.Dvt0W16_.png",d="/RadialBasisFunctions.jl/previews/PR144/assets/divergence_phs_matched.D-w3bqDc.png",l="/RadialBasisFunctions.jl/previews/PR144/assets/divergence_phs_polydeg_sweep.BcuHhE8z.png",h="/RadialBasisFunctions.jl/previews/PR144/assets/curl2d_phs_matched.C5qlPPW7.png",p="/RadialBasisFunctions.jl/previews/PR144/assets/curl2d_phs_polydeg_sweep.DhmxeLCx.png",f=JSON.parse('{"title":"Vector & Higher-Rank Operators","description":"","frontmatter":{},"headers":[],"relativePath":"guides/convergence/vector-operators.md","filePath":"guides/convergence/vector-operators.md","lastUpdated":null}'),m={name:"guides/convergence/vector-operators.md"};function u(g,e,H,P,_,v){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="Vector-and-Higher-Rank-Operators" tabindex="-1">Vector &amp; Higher-Rank Operators <a class="header-anchor" href="#Vector-and-Higher-Rank-Operators" aria-label="Permalink to &quot;Vector &amp; Higher-Rank Operators {#Vector-and-Higher-Rank-Operators}&quot;">​</a></h1><p>Convergence for operators that produce tensor output or act on vector fields: <code>hessian</code>, <code>jacobian</code>, <code>divergence</code>, <code>curl</code>. The test vector field is <code>u(x) = [sin(πx₁) + 0.5cos(2πx₂), exp(x₁x₂)]</code> on <code>[0,1]²</code> with all components having nonzero partials.</p><p>&quot;Which PHS order?&quot; plots below show PHS3/5/7 at fixed <code>poly_deg = 3</code>. Holding the polynomial augmentation constant isolates the PHS-order effect: curves should be parallel on log-log, differing only in the error constant.</p><p>IMQ and Gaussian h-refinement is covered on its own page (<a href="./shape-parameter-bases">Shape-Parameter Bases</a>) — shape-parameter behavior is dominated by the ε-vs-spacing interaction and is discussed there for a representative subset of operators.</p><h2 id="Hessian" tabindex="-1">Hessian <a class="header-anchor" href="#Hessian" aria-label="Permalink to &quot;Hessian {#Hessian}&quot;">​</a></h2><p>The Hessian assembles second partials <code>∂²u/∂xᵢ∂xⱼ</code> into an <code>N × D × D</code> tensor. Error is reported as a Frobenius NRMSE. Because one of the four entries is a mixed partial, the Hessian inherits the mixed-partial caveat — the non-converging combos are the same as for the <a href="/RadialBasisFunctions.jl/previews/PR144/guides/convergence/scalar-operators#mixed-partial-xxj">mixed partial</a> operator.</p><div class="warning custom-block"><p class="custom-block-title">Excluded combinations</p><p>Same PHS set as mixed partial: <code>PHS1/p=1</code>, <code>PHS3/p=1</code>, <code>PHS3/p=2</code>, <code>PHS5/p=2</code> are omitted. <strong>Use PHS5/p=3 or higher for the full Hessian.</strong> Shape-parameter bases: see <a href="./shape-parameter-bases">Shape-Parameter Bases</a>.</p></div><h3 id="Which-PHS-order?" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?}&quot;">​</a></h3><p><img src="'+i+'" alt=""></p><p>At <code>poly_deg = 3</code>, all three PHS orders converge at <code>O(h²)</code> (the second-derivative rate). PHS7 has the smallest error constant.</p><h3 id="How-much-polynomial-degree?" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?}&quot;">​</a></h3><p><img src="'+t+'" alt=""></p><h2 id="Jacobian" tabindex="-1">Jacobian <a class="header-anchor" href="#Jacobian" aria-label="Permalink to &quot;Jacobian {#Jacobian}&quot;">​</a></h2><p>The Jacobian of a vector field is an <code>N × Dᵢₙ × Dₒᵤₜ</code> tensor of first partials — no second derivatives, no mixed-partial issue. Convergence matches the gradient cleanly.</p><h3 id="Which-PHS-order?-2" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-2" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-2}&quot;">​</a></h3><p><img src="'+c+'" alt=""></p><p>Parallel <code>O(h³)</code> curves across PHS3/5/7.</p><h3 id="How-much-polynomial-degree?-2" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-2" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-2}&quot;">​</a></h3><p><img src="'+n+'" alt=""></p><h2 id="Divergence-·" tabindex="-1">Divergence (∇·) <a class="header-anchor" href="#Divergence-·" aria-label="Permalink to &quot;Divergence (∇·) {#Divergence-·}&quot;">​</a></h2><p><code>∇·u = ∂u₁/∂x₁ + ∂u₂/∂x₂</code> — a sum of first partials. Convergence rates match the gradient; all PHS orders at matched poly_deg are well-behaved.</p><h3 id="Which-PHS-order?-3" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-3" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-3}&quot;">​</a></h3><p><img src="'+d+'" alt=""></p><p>Parallel <code>O(h³)</code> curves across PHS3/5/7.</p><h3 id="How-much-polynomial-degree?-3" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-3" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-3}&quot;">​</a></h3><p><img src="'+l+'" alt=""></p><h2 id="Curl-,-2D" tabindex="-1">Curl (∇×, 2D) <a class="header-anchor" href="#Curl-,-2D" aria-label="Permalink to &quot;Curl (∇×, 2D) {#Curl-,-2D}&quot;">​</a></h2><p>In 2D, <code>∇×u = ∂u₂/∂x₁ − ∂u₁/∂x₂</code> (the scalar z-component). Like divergence, this is a first-derivative operator and follows the same convergence profile.</p><h3 id="Which-PHS-order?-4" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-4" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-4}&quot;">​</a></h3><p><img src="'+h+'" alt=""></p><p>Parallel <code>O(h³)</code> curves across PHS3/5/7.</p><h3 id="How-much-polynomial-degree?-4" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-4" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-4}&quot;">​</a></h3><p><img src="'+p+'" alt=""></p>',33)])])}const S=a(m,[["render",u]]);export{f as __pageData,S as default};
